/**
 * LISTADOR ROBUSTO v47.23 - EXTRACCIÓN ULTRA-FLEXIBLE
 */
const items = $input.all();
const archivos = [];

for (let i = 0; i < items.length; i++) {
    const j = items[i].json;
    // Busqueda "ciega": miramos todos los valores de todas las propiedades
    Object.keys(j).forEach(key => {
        const valor = j[key];
        if (valor && typeof valor === 'string' && valor.toLowerCase().indexOf('.xlsx') !== -1) {
            if (valor.indexOf('~$') === -1) {
                archivos.push(valor.trim());
            }
        }
    });
}

// Limpiar duplicados de forma compatible
const unicos = [];
archivos.forEach(a => { if(unicos.indexOf(a) === -1) unicos.push(a); });

return [{
  json: {
    estado: unicos.length > 0 ? "EXITO" : "ADVERTENCIA",
    conteo: unicos.length,
    archivos: unicos,
    lista_texto: unicos.length > 0 
      ? "Archivos detectados: " + unicos.join(', ') 
      : "No se encontraron nombres válidos en el archivo procesado."
  }
}];
